#!/usr/bin/env python3\n\"\"\"\nReal Market Data Collector for AI Training\nCollects comprehensive historical market data for advanced AI model training\n\"\"\"\n\nimport os\nimport sys\nimport pandas as pd\nimport numpy as np\nimport requests\nimport sqlite3\nimport ccxt\nfrom datetime import datetime, timedelta\nimport time\nimport json\nfrom pathlib import Path\nimport logging\nfrom typing import Dict, List, Optional\n\n# Setup logging\nlogging.basicConfig(\n    level=logging.INFO,\n    format='%(asctime)s - DataCollector - %(levelname)s - %(message)s'\n)\nlogger = logging.getLogger(__name__)\n\nclass RealMarketDataCollector:\n    \"\"\"Comprehensive real market data collector for AI training\"\"\"\n    \n    def __init__(self):\n        self.db_path = \"market_training_data.db\"\n        self.data_dir = Path(\"training_data\")\n        self.data_dir.mkdir(exist_ok=True)\n        \n        # Initialize exchange clients\n        self.exchanges = self._initialize_exchanges()\n        \n        # Trading pairs to collect\n        self.trading_pairs = [\n            'BTCUSDT', 'ETHUSDT', 'ADAUSDT', 'DOTUSDT', 'LINKUSDT',\n            'BNBUSDT', 'XRPUSDT', 'LTCUSDT', 'BCHUSDT', 'EOSUSDT'\n        ]\n        \n        # Timeframes to collect  \n        self.timeframes = ['1h', '4h', '1d']\n        \n        # Initialize database\n        self._init_database()\n        \n        logger.info(\"Real Market Data Collector initialized\")\n    \n    def _initialize_exchanges(self) -> Dict:\n        \"\"\"Initialize exchange connections\"\"\"\n        exchanges = {}\n        \n        try:\n            # Binance (primary)\n            exchanges['binance'] = ccxt.binance({\n                'apiKey': os.getenv('BINANCE_API_KEY', ''),\n                'secret': os.getenv('BINANCE_SECRET_KEY', ''),\n                'sandbox': os.getenv('BINANCE_TESTNET', 'true').lower() == 'true',\n                'enableRateLimit': True,\n                'options': {\n                    'defaultType': 'spot'\n                }\n            })\n            logger.info(\"✅ Binance exchange initialized\")\n        except Exception as e:\n            logger.error(f\"❌ Failed to initialize Binance: {e}\")\n        \n        return exchanges\n    \n    def _init_database(self):\n        \"\"\"Initialize SQLite database for storing market data\"\"\"\n        try:\n            conn = sqlite3.connect(self.db_path)\n            cursor = conn.cursor()\n            \n            # Create market data table\n            cursor.execute(\"\"\"\n                CREATE TABLE IF NOT EXISTS market_data (\n                    id INTEGER PRIMARY KEY AUTOINCREMENT,\n                    symbol TEXT NOT NULL,\n                    timeframe TEXT NOT NULL,\n                    timestamp INTEGER NOT NULL,\n                    open REAL NOT NULL,\n                    high REAL NOT NULL,\n                    low REAL NOT NULL,\n                    close REAL NOT NULL,\n                    volume REAL NOT NULL,\n                    exchange TEXT DEFAULT 'binance',\n                    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n                    UNIQUE(symbol, timeframe, timestamp, exchange)\n                )\n            \"\"\")\n            \n            conn.commit()\n            conn.close()\n            logger.info(\"✅ Database initialized successfully\")\n            \n        except Exception as e:\n            logger.error(f\"❌ Failed to initialize database: {e}\")\n    \n    def collect_historical_data(self, symbol: str, timeframe: str, \n                              days_back: int = 30) -> pd.DataFrame:\n        \"\"\"Collect historical OHLCV data\"\"\"\n        \n        if 'binance' not in self.exchanges:\n            logger.error(\"Binance exchange not available\")\n            return pd.DataFrame()\n        \n        exchange = self.exchanges['binance']\n        \n        try:\n            # Calculate limit based on timeframe\n            timeframe_hours = {'1h': 1, '4h': 4, '1d': 24}\n            hours_per_candle = timeframe_hours.get(timeframe, 1)\n            limit = min(1000, (days_back * 24) // hours_per_candle)\n            \n            logger.info(f\"📊 Collecting {limit} candles of {symbol} {timeframe}...\")\n            \n            # Fetch OHLCV data\n            ohlcv = exchange.fetch_ohlcv(symbol, timeframe, limit=limit)\n            \n            if not ohlcv:\n                logger.warning(f\"No data received for {symbol} {timeframe}\")\n                return pd.DataFrame()\n            \n            # Convert to DataFrame\n            df = pd.DataFrame(ohlcv, columns=['timestamp', 'open', 'high', 'low', 'close', 'volume'])\n            df['timestamp'] = pd.to_datetime(df['timestamp'], unit='ms')\n            df['symbol'] = symbol\n            df['timeframe'] = timeframe\n            \n            logger.info(f\"✅ Collected {len(df)} records for {symbol} {timeframe}\")\n            return df\n            \n        except Exception as e:\n            logger.error(f\"❌ Failed to collect data for {symbol} {timeframe}: {e}\")\n            return pd.DataFrame()\n    \n    def store_data_to_db(self, df: pd.DataFrame):\n        \"\"\"Store market data to database\"\"\"\n        if df.empty:\n            return\n        \n        try:\n            conn = sqlite3.connect(self.db_path)\n            \n            # Prepare data for insertion\n            data_to_insert = []\n            for _, row in df.iterrows():\n                data_to_insert.append((\n                    row['symbol'],\n                    row['timeframe'],\n                    int(row['timestamp'].timestamp() * 1000),\n                    float(row['open']),\n                    float(row['high']),\n                    float(row['low']),\n                    float(row['close']),\n                    float(row['volume']),\n                    'binance'\n                ))\n            \n            # Insert with conflict resolution\n            cursor = conn.cursor()\n            cursor.executemany(\"\"\"\n                INSERT OR REPLACE INTO market_data \n                (symbol, timeframe, timestamp, open, high, low, close, volume, exchange)\n                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)\n            \"\"\", data_to_insert)\n            \n            conn.commit()\n            conn.close()\n            \n            logger.info(f\"✅ Stored {len(data_to_insert)} records to database\")\n            \n        except Exception as e:\n            logger.error(f\"❌ Failed to store data to database: {e}\")\n    \n    def collect_comprehensive_dataset(self, days_back: int = 7):\n        \"\"\"Collect comprehensive dataset for all pairs and timeframes\"\"\"\n        \n        logger.info(f\"🚀 Starting data collection for {days_back} days\")\n        logger.info(f\"📊 Pairs: {len(self.trading_pairs)}\")\n        logger.info(f\"⏰ Timeframes: {len(self.timeframes)}\")\n        \n        total_collections = len(self.trading_pairs) * len(self.timeframes)\n        completed = 0\n        \n        for symbol in self.trading_pairs:\n            for timeframe in self.timeframes:\n                try:\n                    logger.info(f\"📈 [{completed+1}/{total_collections}] Collecting {symbol} {timeframe}...\")\n                    \n                    # Collect data\n                    df = self.collect_historical_data(symbol, timeframe, days_back)\n                    \n                    if not df.empty:\n                        # Store to database\n                        self.store_data_to_db(df)\n                    \n                    completed += 1\n                    \n                    # Rate limiting\n                    time.sleep(1)\n                    \n                except Exception as e:\n                    logger.error(f\"❌ Failed to collect {symbol} {timeframe}: {e}\")\n                    completed += 1\n                    continue\n        \n        logger.info(f\"🎉 Data collection complete! {completed}/{total_collections} collections\")\n        self._generate_summary()\n    \n    def _generate_summary(self):\n        \"\"\"Generate summary of collected data\"\"\"\n        try:\n            conn = sqlite3.connect(self.db_path)\n            cursor = conn.cursor()\n            cursor.execute(\"SELECT COUNT(*) FROM market_data\")\n            total_records = cursor.fetchone()[0]\n            \n            cursor.execute(\"\"\"\n                SELECT symbol, timeframe, COUNT(*) as count\n                FROM market_data \n                GROUP BY symbol, timeframe\n                ORDER BY symbol, timeframe\n            \"\"\")\n            \n            stats = cursor.fetchall()\n            conn.close()\n            \n            logger.info(f\"📊 DATA SUMMARY\")\n            logger.info(f\"Total Records: {total_records:,}\")\n            logger.info(f\"Pairs: {len(set(s[0] for s in stats))}\")\n            logger.info(f\"Timeframes: {len(set(s[1] for s in stats))}\")\n            \n        except Exception as e:\n            logger.error(f\"❌ Failed to generate summary: {e}\")\n    \n    def get_training_data(self, timeframe: str = '1h', limit: int = 5000) -> pd.DataFrame:\n        \"\"\"Get training data from database\"\"\"\n        try:\n            conn = sqlite3.connect(self.db_path)\n            \n            query = \"\"\"\n                SELECT timestamp, open, high, low, close, volume, symbol\n                FROM market_data \n                WHERE timeframe = ?\n                ORDER BY timestamp DESC\n                LIMIT ?\n            \"\"\"\n            \n            df = pd.read_sql_query(query, conn, params=(timeframe, limit))\n            conn.close()\n            \n            if not df.empty:\n                df['timestamp'] = pd.to_datetime(df['timestamp'], unit='ms')\n                df = df.sort_values('timestamp').reset_index(drop=True)\n                logger.info(f\"✅ Retrieved {len(df)} training records\")\n            \n            return df\n            \n        except Exception as e:\n            logger.error(f\"❌ Failed to get training data: {e}\")\n            return pd.DataFrame()\n\ndef main():\n    \"\"\"Main function to collect real market data\"\"\"\n    \n    print(\"🚀 Real Market Data Collector for AI Training\")\n    print(\"=\" * 60)\n    \n    collector = RealMarketDataCollector()\n    \n    # Collect data\n    print(\"\\n📊 Starting data collection...\")\n    print(\"This will collect 7 days of historical data\")\n    print(f\"   • {len(collector.trading_pairs)} trading pairs\")\n    print(f\"   • {len(collector.timeframes)} timeframes\")\n    \n    collector.collect_comprehensive_dataset(days_back=7)\n    \n    # Get sample data\n    print(\"\\n📤 Checking collected data...\")\n    df = collector.get_training_data('1h', 100)\n    \n    if not df.empty:\n        print(f\"\\n🎉 SUCCESS! Collected {len(df)} records\")\n        print(f\"📊 Data shape: {df.shape}\")\n        print(f\"📅 Date range: {df['timestamp'].min()} to {df['timestamp'].max()}\")\n        print(f\"💱 Symbols: {df['symbol'].unique()}\")\n        \n        # Save sample to CSV\n        df.to_csv('training_data/sample_data.csv', index=False)\n        print(\"\\n💾 Sample data saved to training_data/sample_data.csv\")\n        \n        print(\"\\n🔥 Next steps:\")\n        print(\"   1. Your real market data is now ready!\")\n        print(\"   2. The advanced AI models can now train on this data\")\n        print(\"   3. Run your training systems to see improved performance!\")\n    else:\n        print(\"\\n❌ No data collected - check your API connection\")\n    \n    print(\"\\n\" + \"=\"*60)\n\nif __name__ == \"__main__\":\n    main()" 